const cfg = $input.first().json;
const now = new Date();
const parts = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'America/Sao_Paulo', weekday: 'short', hour: '2-digit', minute: '2-digit', hourCycle: 'h23'
}).formatToParts(now).reduce((acc, part) => (acc[part.type] = part.value, acc), {});
const weekdays = {Mon:1,Tue:2,Wed:3,Thu:4,Fri:5,Sat:6,Sun:7};
const day = weekdays[parts.weekday];
const minutes = Number(parts.hour) * 60 + Number(parts.minute);
const start = 8 * 60;
const end = 19 * 60;
const automaticSlot = day <= 6 && minutes >= start && minutes <= end && ((minutes - start) % 45 <= 14);
if (!cfg.forcar_envio && !automaticSlot) return [];
if (!String(cfg.grupo_id || '').endsWith('@g.us') || String(cfg.grupo_id).startsWith('COLE_')) {
  throw new Error('Informe o grupo_id real no node de configuração. Ele deve terminar com @g.us.');
}
if (!/^https?:\/\//i.test(String(cfg.site_public_url || ''))) {
  throw new Error('Informe a URL pública do site no node de configuração.');
}
return [{json: cfg}];

const v = $input.first().json;
const money = (value) => {
  const n = Number(value);
  return Number.isFinite(n) && n > 0 ? new Intl.NumberFormat('pt-BR',{style:'currency',currency:'BRL'}).format(n) : 'A combinar';
};
const list = (value) => String(value || '').split(/\r?\n|;|\|/).map(x => x.trim().replace(/^[-•*]\s*/, '')).filter(Boolean);
const phoneDigits = String(v.telefone_divulgacao || '11913022278').replace(/\D/g,'');
const phone = phoneDigits.length === 11 ? `(${phoneDigits.slice(0,2)}) ${phoneDigits.slice(2,7)}-${phoneDigits.slice(7)}` : phoneDigits;
const location = [v.bairro, v.cidade].filter(Boolean).join(' — ') || 'Local a combinar';
const schedule = [v.escala ? `Escala ${v.escala}` : '', v.horario ? `Horário ${v.horario}` : ''].filter(Boolean).join(' · ') || 'A confirmar';
const benefits = list(v.beneficios).slice(0,6).join(', ') || 'Informados no processo seletivo';
const unhealthy = v.possui_insalubridade === true || String(v.possui_insalubridade).toLowerCase() === 'true';
const percent = Number(v.percentual_insalubridade);
const insalubridade = unhealthy ? `🧪 Insalubridade: ${Number.isFinite(percent) ? `${percent}%` : 'percentual a confirmar'}` : '';
const caption = [
  `*${v.titulo || v.cargo} | Início imediato*`,
  `📍 ${location}`,
  `🕐 ${schedule}`,
  `💰 Salário: ${money(v.salario)}`,
  insalubridade,
  `🎁 Benefícios: ${benefits}`,
  '',
  `📲 Para mais informações, chame no privado: ${phone}`
].filter(line => line !== '').join('\n');
const token = encodeURIComponent(String(v.public_token || ''));
const imageUrl = `${String(v.site_public_url).replace(/\/$/,'')}/api/public/vagas/${v.id}/divulgacao/principal.png?token=${token}`;
return [{json:{...v, session:v.sessao_waha, chatId:v.grupo_id, caption, image_url:imageUrl, filename:`${v.codigo || `vaga-${v.id}`}-divulgacao.png`}}];

